"""
MKT Original Commentary — Genesis chapters 20–23
Run: python3 scripts/zc-original-genesis-20-23.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 20: the Abimelech narrative uses ʾĔlōhîm (not YHWH) throughout; this is not
  accident — the pagan king's divine revelation comes through the generic El-class
  name; Abraham is called nāḇîʾ (prophet) for the first time in Scripture here
- Ch 21: mĕṣaḥēq (v9, Ishmael mocking) is the same root as Yiṣḥāq (Isaac's name);
  the wordplay is crucial to the narrative irony; Paul's reading in Gal 4:29 as
  persecution is not imposed but reads the context of expulsion and covenant
  narrowing; bĕyiṣḥāq yiqqārēʾ lĕḵā zeraʿ (v12) = the covenant narrows through
  Isaac alone, not through all biological offspring
- Ch 22: v14 already present in JSON; skipped in this dictionary; the Akedah is
  the most typologically dense passage in Genesis; the commentary focuses on
  the Hebrew verbal/syntactic level (what the grammar says) not on what theology
  the reader should draw — that is the mkt-christ layer's task
- Ch 23: the Machpelah purchase is a legally precise ANE real-estate transaction;
  the formula gēr-wĕtôšāḇ (sojourner and resident) is Abraham's legal self-title;
  the purchase price (400 shekels) and weighing are commercial realism
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "20": {
    "1": '<p><strong>וַיָּגָר בִּגְרָר</strong> (<em>wayyāḡār biḡrār</em>) — "he sojourned in Gerar." <em>Gûr</em> (to sojourn, dwell as a resident alien) — the same verb that defines Abraham\'s entire existence in Canaan (17:8; 21:23; 26:3; 28:4). Gerar is a Philistine city in the Negev region (between Kadesh and Shur) — the territory of a settled people with their own political structure. The narrative repeats the wife-sister motif of ch. 12 in a new setting; this is the second of the three iterations (12:10-20; here; 26:6-11 with Isaac and Rebekah).</p>',
    "2": '<p><strong>אֲחֹתִי הִוא</strong> (<em>ʾăḥōtî hîʾ</em>, she is my sister) — the same deception formula as 12:13, now enacted in Philistine territory. <em>Aḇîmelek melek-gĕrār</em> (Abimelech king of Gerar) — <em>Aḇîmelek</em> = "my father is king" (a throne name or hereditary title in the region; used for multiple Philistine rulers: cf. 26:1; Ps 34 superscript). <strong>וַיִּשְׁלַח אֲבִימֶלֶךְ</strong> — sent for Sarah: the king\'s acquisition of a woman for his household is a royal prerogative in the ANE; the danger to the covenant line is immediate and concrete.</p>',
    "3": '<p><strong>וַיָּבֹא אֱלֹהִים אֶל-אֲבִימֶלֶךְ בַּחֲלוֹם הַלָּיְלָה</strong> — "God came to Abimelech in a dream of the night." The divine name throughout ch. 20 is <em>ʾĔlōhîm</em> (God), not <em>YHWH</em> — the generic Semitic divine name rather than the covenant name. This is consistent with the chapter\'s setting in a non-Israelite context: God is revealing himself to a Philistine king through the form of divine communication available to all peoples (dreams — cf. Gen 41; Dan 2). <strong>הִנְּךָ מֵת</strong> (<em>hinnĕḵā mēt</em>, you are as good as dead) — the participial construction (hinneḵā + participle) expresses an imminent or already-determined state: "behold you [are] dead." The death-sentence is delivered before any wrongdoing has occurred, emphasizing that God\'s intervention precedes Abimelech\'s potential sin.</p>',
    "4": '<p><strong>הֲגוֹי גַּם-צַדִּיק תַּהֲרֹג</strong> (<em>hăgôy gam-ṣaddîq taharōḡ</em>) — "will you destroy even a righteous nation?" Abimelech uses <em>ʾAḏōnāy</em> (Lord/Sovereign) — the Hebrew honorific used by Israelites before YHWH, suggesting that the narrator considers Abimelech\'s recognition of God as genuine. <em>Ṣaddîq</em> (righteous, in the right) — Abimelech claims moral innocence, using the covenant-justice vocabulary (<em>ṣĕḏāqāh</em> field of meaning). The question echoes Abraham\'s own challenge to divine justice in 18:25 ("will the judge of all the earth not do justice?") — a pagan king makes the same moral argument as the covenant patriarch.</p>',
    "5": '<p><strong>בְּתָם-לְבָבִי וּבְנִקְיֹן כַּפַּי</strong> (<em>bĕtom-lĕbābî ûbĕniqyōn kappāy</em>) — "with the integrity of my heart and the cleanness of my hands." <em>Tōm</em> (wholeness, integrity) of the heart and <em>niqyōn</em> (cleanness, innocence) of the hands — the combination appears in Ps 24:4 (the worshipper who may ascend YHWH\'s mountain) and Ps 26:6; the moral idiom of clean hands/pure heart is a covenant-piety formula applied here by a non-Israelite king. Abimelech\'s self-defense is complete and legitimate — he acted on the information given.</p>',
    "6": '<p><strong>גַּם אָנֹכִי יָדַעְתִּי כִּי בְתָם-לְבָבְךָ עָשִׂיתָ זֹּאת</strong> — "Yes, I myself also knew that you did this with the integrity of your heart." God confirms Abimelech\'s innocence — divine omniscience vindicates the claim. <strong>וָאֶחְשֹׂךְ גַּם-אָנֹכִי אוֹתְךָ מֵחֲטוֹ-לִי</strong> — "and I myself also withheld you from sinning against me." <em>Ḥāśaḵ</em> (to withhold, restrain, hold back) — God actively prevented Abimelech from sinning by means of the physical situation (not letting him touch Sarah). The divine protection operates at the providential level: God manages the circumstances to prevent the sin, then warns the king to reverse the situation.</p>',
    "7": '<p><strong>כִּי-נָבִיא הוּא</strong> (<em>kî-nāḇîʾ hûʾ</em>, for he is a prophet) — the first and only time Abraham is explicitly called a <em>nāḇîʾ</em> (prophet) in Genesis. <em>Nāḇîʾ</em> — the Hebrew term for prophet (from <em>nābaʾ</em>, to speak as a mouthpiece; or possibly related to Akkadian <em>nabû</em>, to call/name). The prophetic office is here defined functionally: the prophet intercedes (יִתְפַּלֵּל, Hithpael of <em>pālal</em>, to pray/intercede) on behalf of others. Abraham\'s prophetic role is intercessory — he will pray for Abimelech\'s household (vv. 17-18). This is the OT\'s first connection between prophecy and intercession.</p>',
    "8": '<p><strong>וַיַּשְׁכֵּם אֲבִימֶלֶךְ בַּבֹּקֶר</strong> — "Abimelech rose early in the morning." <em>Hiškîm</em> (Hiphil, to rise early) — the same word used for Abraham\'s early rising in 22:3 (for the Akedah) and 21:14 (to send Hagar away). The urgency of rising early marks responsiveness to divine word. <em>Wayyiqrāʾ lĕḵol-ʿăḇāḏāyw</em> (he summoned all his servants) — the king immediately marshals his household officials to deal with the divine threat, indicating he takes the dream-warning with complete seriousness.</p>',
    "9": '<p><strong>מַה-עָשִׂיתָ לָּנוּ</strong> (<em>mah-ʿāśîtā lānû</em>) — "what have you done to us?" Abimelech\'s reproach mirrors exactly the formula of divine judicial inquiry (3:13; 4:10; 12:18) — and Pharaoh\'s rebuke in 12:18 used the same words. <strong>מַעֲשִׂים אֲשֶׁר לֹא-יֵעָשׂוּ</strong> (<em>maʿăśîm ʾăšer lōʾ-yēʿāśû</em>) — "deeds that should not be done." The Niphal passive construction with <em>lōʾ</em> creates a categorical prohibition: these are actions that lie outside the bounds of acceptable conduct. The pagan king invokes a moral absolute — a recognition of universal ethical norms independent of covenant. The reproach is the same as in 12:18-19: the moral credibility of the covenant family is implicated.</p>',
    "10": '<p><strong>מָה רָאִיתָ כִּי עָשִׂיתָ אֶת-הַדָּבָר הַזֶּה</strong> — "what did you see, that you did this thing?" <em>Rāʾāh</em> (to see, perceive) in the sense of: what assessment, what observation of the situation led you to this action? The question asks for the underlying reasoning — not just what happened but why. Abraham\'s answer in vv. 11-13 is the longest self-defense in the patriarchal narratives, revealing his theological reasoning and domestic arrangement.</p>',
    "11": '<p><strong>אַךְ אֵין-יִרְאַת אֱלֹהִים בַּמָּקוֹם הַזֶּה</strong> — "surely there is no fear of God in this place." <em>Yirʾat ʾĔlōhîm</em> (fear of God) — the phrase that in Proverbs 1:7 is "the beginning of wisdom" and that defines the morally ordered community; Abraham assumed that without YHWH-worship there would be no moral restraint. The narrative immediately subverts his assumption: Abimelech shows more moral sensitivity than Abraham. The patriarchal character is presented without sanitizing — Abraham\'s fear-based reasoning led to a deceptive action that placed his wife in danger.</p>',
    "12": '<p><strong>וְגַם-אָמְנָה אֲחֹתִי בַת-אָבִי הִוא אַךְ לֹא בַת-אִמִּי</strong> — "and indeed she is truly my sister, daughter of my father, though not daughter of my mother." The half-sibling relationship between Abraham and Sarah (same father, different mothers) is revealed here for the first time. This makes the deception technically a half-truth — she is his half-sister — while functionally deceptive since she is also his wife. The law of Lev 18:9; 20:17 would prohibit this marriage, but the patriarchal narrative precedes the Sinai legislation and presents the situation without anachronistic condemnation.</p>',
    "13": '<p><strong>כַּאֲשֶׁר הִתְעוּ אֹתִי אֱלֹהִים מִבֵּית אָבִי</strong> — "when God caused me to wander from my father\'s household." <em>Tāʿāh</em> (Hiphil: to cause to wander, lead astray) — with God as subject, this is not a negative but a description of the nomadic calling: God led Abraham out in a wandering way. The same verb in Ps 107:4 ("they wandered in the desert wasteland") describes Israel\'s wilderness sojourn as divine leading-through-wandering. Abraham\'s self-account frames the journey as divine leading; the wife-sister agreement was a precaution for that wandering. <strong>עַשְׂי חַסְדֵּךְ</strong> (<em>ʿaśî ḥasdêḵ</em>, do your covenant-loyalty/kindness to me) — <em>ḥeseḏ</em> (covenant loyalty, steadfast love) as the basis of the domestic agreement.</p>',
    "14": '<p><strong>וַיִּקַּח אֲבִימֶלֶךְ צֹאן וּבָקָר וַעֲבָדִים וּשְׁפָחֹת</strong> — Abimelech\'s restitution mirrors Pharaoh\'s gifts in 12:16 — the same categories (sheep and cattle, male and female slaves). The parallel is deliberate: both pagan rulers respond to the divine threat by enriching Abraham; the material wealth of the covenant family grows through these encounters. The return of Sarah is the primary act: the goods are accompaniment to restoration of the wife.</p>',
    "15": '<p><strong>הִנֵּה אַרְצִי לְפָנֶיךָ</strong> (<em>hinnēh ʾarṣî lĕpānêḵā</em>, behold my land is before you) — Abimelech offers Abraham open access to his territory; the formula "the land is before you" echoes Abraham\'s offer to Lot in 13:9 and the covenant land-promise (cf. Deut 1:8; 4:1). <em>Bĕṭôḇ bĕʿênêḵā šēḇ</em> (wherever is good in your eyes, dwell) — the idiom of personal choice and sovereign hospitality; Abimelech grants Abraham the right to settle anywhere in Gerar\'s territory.</p>',
    "16": '<p><strong>הִנֵּה הוּא-לְךָ כְּסוּת עֵינַיִם</strong> (<em>hinnēh hûʾ-lĕḵā kĕsût ʿênāyim</em>, behold it is for you a covering of eyes) — the thousand shekels of silver is described as a "covering of eyes." The phrase <em>kĕsût ʿênāyim</em> is rare and its precise meaning is debated: (1) something that averts others\' eyes from the offense — a payment to make people overlook what happened; (2) a face-veil or covering for Sarah\'s honor — restoring her dignity in the eyes of the community; (3) compensation for the "unveiled" or "uncovered" offense. The LXX reads "this shall be for you for the honor of your face" (τοῦτό σοι εἰς τιμήν). Whatever the precise idiom, the silver is restorative: <strong>וְנֹכַחַת לְכֹל</strong> — "you are fully vindicated/set right before all."</p>',
    "17": '<p><strong>וַיִּתְפַּלֵּל אַבְרָהָם אֶל-הָאֱלֹהִים</strong> — "Abraham prayed to God." <em>Hitpallēl</em> (Hithpael of <em>pālal</em>, to intercede, pray) — the prophetic intercessory role announced in v. 7 is now fulfilled. Abraham prays for the pagan king\'s household — one of the clearest instances of the OT\'s intercessory prayer on behalf of non-Israelites. <strong>וַיִּרְפָּא אֱלֹהִים אֶת-אֲבִימֶלֶךְ</strong> — "and God healed Abimelech." <em>Rāpāʾ</em> (to heal) — healing as the restoration of divine blessing; the wombs closed by God\'s judgment (v. 18) are reopened by God\'s grace through prophetic intercession.</p>',
    "18": '<p><strong>כִּי-עָצֹר עָצַר יְהוָה בְּעַד כָּל-רֶחֶם</strong> (<em>kî-ʿāṣōr ʿāṣar YHWH bĕʿaḏ kol-reḥem</em>) — "for the LORD had tightly closed (<em>infinitive absolute</em> + verb) every womb." The emphatic infinitive absolute <em>ʿāṣōr ʿāṣar</em> (surely shut up, firmly closed) uses the same verb as 16:2 where Sarai says "the LORD has shut me up from bearing." The closing of the Abimelech household\'s wombs is YHWH\'s name for the first time in the chapter — the narrator reveals that the divine action protecting Sarah was specifically YHWH even in this Elohim-narrative. The irony: the patriarch whose wife is barren temporarily makes others barren by his deception.</p>'
  },
  "21": {
    "1": '<p><strong>וַיהוָה פָּקַד אֶת-שָׂרָה</strong> (<em>waYHWH pāqaḏ ʾet-śārāh</em>) — "the LORD visited Sarah." <em>Pāqaḏ</em> (to visit, attend to, appoint, muster) — a verb with two contrasting senses that must be determined from context: divine visitation in blessing (Ruth 1:6; 1 Sam 2:21; Luke 1:68: "he has visited/redeemed his people") and divine visitation in judgment (Exod 32:34; Amos 3:2). Here unambiguously blessing: God fulfills the promise of 17:16-21 and 18:10. The covenantal attention expressed by <em>pāqaḏ</em> is intimate and purposeful — God did not merely allow nature to take its course; he attended to Sarah specifically.</p>',
    "2": '<p><strong>לַמּוֹעֵד אֲשֶׁר-דִּבֶּר אֹתוֹ אֱלֹהִים</strong> (<em>lammôʿēḏ ʾăšer-dibbēr ʾōtô ʾĔlōhîm</em>) — "at the appointed time that God had spoken." <em>Môʿēḏ</em> (appointed time, fixed season, set meeting) — the same word used for the sacred assembly times of Israel\'s festival calendar (Lev 23; Num 28-29). Isaac\'s birth is at a divinely appointed <em>môʿēḏ</em>, not a random biological event — the covenant heir arrives at God\'s chosen moment, on God\'s schedule (announced in 18:10: "at the appointed time I will return to you").</p>',
    "3": '<p><strong>וַיִּקְרָא אַבְרָהָם אֶת-שֶׁם-בְּנוֹ הַנּוֹלַד-לוֹ אֲשֶׁר-יָלְדָה-לּוֹ שָׂרָה יִצְחָק</strong> — "Abraham called the name of his son who was born to him, whom Sarah bore him, Isaac." <em>Yiṣḥāq</em> (Isaac) = "he laughs / he will laugh" — from <em>ṣāḥaq</em> (to laugh); God specified this name in 17:19 ("you will call his name Isaac"). The name encodes Sarah\'s laughter of disbelief (18:12-13) and Abraham\'s laughter of joyful astonishment (17:17) — both are transformed into the child\'s identity. The name is also the first Hebrew term in the Bible derived from the word for joy/laughter (<em>ṣĕḥōq</em>), suggesting the covenant heir\'s arrival is inherently a cause for rejoicing.</p>',
    "4": '<p><strong>וַיָּמָל אַבְרָהָם אֶת-יִצְחָק בְּנוֹ בֶּן-שְׁמֹנַת יָמִים</strong> — "Abraham circumcised his son Isaac when he was eight days old." The circumcision is performed exactly as commanded in 17:12 ("every male among you eight days old shall be circumcised") — the narrative carefully records that the covenant sign was applied to the covenant heir on the prescribed day. <strong>כַּאֲשֶׁר צִוָּה אֹתוֹ אֱלֹהִים</strong> (as God had commanded him) — the obedience formula; the narrator marks the fulfilled command as the structural point of the verse.</p>',
    "5": '<p><strong>וְאַבְרָהָם בֶּן-מְאַת שָׁנָה</strong> — "and Abraham was a hundred years old." The chronological note emphasizes the impossibility: 100 years old (cf. 17:17; Rom 4:19: "his own body was as good as dead, being about a hundred years old"). The birth of Isaac is presented as a biological impossibility overcome by divine promise — the covenant heir\'s origin is not from natural human capacity but from divine faithfulness to the spoken word.</p>',
    "6": '<p><strong>צְחֹק עָשָׂה-לִּי אֱלֹהִים</strong> (<em>ṣĕḥōq ʿāśāh-lî ʾĔlōhîm</em>) — "God has made laughter for me." <em>Ṣĕḥōq</em> (laughter, mirth) — the same root as Isaac\'s name, now completed: the name was given in anticipation, and the laughter it names has arrived. <strong>כָּל-הַשֹּׁמֵעַ יִצְחַק-לִי</strong> (all who hear will laugh with me/at me) — the verb <em>yiṣḥaq-lî</em> is the jussive form of Isaac\'s name: "everyone who hears will [yiṣḥaq = Isaac]" — the impossible birth makes the name a living event, a standing proclamation of divine power. The ambiguity of "laugh with me" (joy) or "laugh at me" (astonishment) is deliberate in the Hebrew.</p>',
    "7": '<p><strong>מִי מִלֵּל לְאַבְרָהָם הֵינִיקָה בָנִים שָׂרָה</strong> — "Who would have said to Abraham that Sarah would nurse children?" <em>Millēl</em> (Pilpel of <em>mālal</em>, to say, speak — an Aramaicizing form used in poetic or archaic contexts) — a rhetorical impossibility: no human being would have dared to predict it. The nursing detail (<em>hênîqāh bānîm</em>, nurse sons) is specific — Sarah suckles the child, proving she has milk, proving the physiological restoration of a post-menopausal woman. <strong>כִּי-יָלַדְתִּי בֵן לִזְקֻנָיו</strong> (for I have borne a son in his old age) — the son born to an old man; the miracle belongs to both parents.</p>',
    "8": '<p><strong>וַיִּגְדַּל הַיֶּלֶד וַיִּגָּמַל</strong> (<em>wayyiḡdal hayyeleḏ wayyiggāmal</em>) — "the child grew and was weaned." <em>Gāmal</em> (to wean, accomplish, repay, ripen) — the weaning feast marks a significant developmental milestone; ANE practice typically involved nursing for 2-3 years. <strong>מִשְׁתֶּה גָדוֹל</strong> (great feast) — the weaning celebration is a public, community event; Isaac\'s growth from birth to weaning is publicly acknowledged. The feast setting introduces the conflict of vv. 9-10: what Ishmael does, he does during this celebration of Isaac.</p>',
    "9": '<p><strong>וַתֵּרֶא שָׂרָה אֶת-בֶּן-הָגָר הַמִּצְרִית אֲשֶׁר-יָלְדָה לְאַבְרָהָם מְצַחֵק</strong> — "Sarah saw the son of Hagar the Egyptian, whom she had borne to Abraham, mocking/laughing." <em>Mĕṣaḥēq</em> (Piel participle of <em>ṣāḥaq</em>) — the same root as Isaac\'s name (Yiṣḥāq). The Piel of <em>ṣāḥaq</em> has a stronger force than the Qal: the basic meaning is "playing, sporting, laughing," but the Piel elsewhere means "mocking" (39:14, 17 where Potiphar\'s wife accuses Joseph of the same verb), "making sport" with potential sexual or aggressive overtones, or engaging in idol-worship (32:6; Exod 32:6). The LXX simply reads "playing" (<em>paizonta</em>). Paul in Gal 4:29 uses the language of "persecution." The Hebrew text leaves the precise nature deliberately open; the narrative function is clear: Sarah perceives it as a threat to Isaac\'s inheritance.</p>',
    "10": '<p><strong>גָּרֵשׁ הָאָמָה הַזֹּאת וְאֶת-בְּנָהּ</strong> (<em>gārēš hāʾāmāh hazzōʾt wĕʾet-bĕnāh</em>) — "drive out this slave woman and her son." <em>Gāraš</em> (to drive out, expel) — a strong term (used for the expulsion from Eden, 3:24; the driving out of nations, Exod 34:11). Sarah\'s demand is harsh: <em>ʾāmāh</em> (slave woman, maidservant) — she does not call Hagar by name or Ishmael by name; they are reduced to "this slave woman and her son." <strong>לֹא יִירַשׁ בֶּן-הָאָמָה הַזֹּאת עִם-בְּנִי עִם-יִצְחָק</strong> — "the son of this slave woman will not inherit with my son, with Isaac." The legal concern is inheritance: Ishmael, as Abraham\'s firstborn, has a claim; Sarah insists on Isaac\'s exclusive inheritance. The double "with my son, with Isaac" is emphatic contrast.</p>',
    "11": '<p><strong>וַיֵּרַע הַדָּבָר מְאֹד בְּעֵינֵי אַבְרָהָם</strong> — "the matter was very displeasing to Abraham." <em>Rāʿaʿ</em> (to be evil, bad, displeasing) — the idiom <em>rāʿaʿ bĕʿênê</em> (evil/bad in the eyes of) is the standard formula for moral/emotional displeasure. <strong>עַל אוֹדֹת בְּנוֹ</strong> (on account of his son) — it is Ishmael Abraham grieves for: his firstborn, 13 years old at Isaac\'s birth (17:25), now being expelled. The narrative presents Abraham\'s grief as genuine parental love for Ishmael — the covenant narrowing is painful, not indifferent.</p>',
    "12": '<p><strong>כִּי בְיִצְחָק יִקָּרֵא לְךָ זָרַע</strong> (<em>kî ḇĕyiṣḥāq yiqqārēʾ lĕḵā zeraʿ</em>) — "for through Isaac your offspring will be named/reckoned." The Niphal <em>yiqqārēʾ</em> (will be called, reckoned) — the covenant line passes through Isaac alone; Ishmael\'s exclusion is not rejection of Ishmael as a person but narrowing of the covenant inheritance. Paul cites this verse in Rom 9:7 and Heb 11:18 to make the theological point that physical descent alone does not define covenant membership — "not all who are descended from Israel are Israel" (Rom 9:6). The preposition <em>bĕ</em> (in/through Isaac) is partitive: only through this line.</p>',
    "13": '<p><strong>וְגַם אֶת-בֶּן-הָאָמָה לְגוֹי אֲשִׂימֶנּוּ</strong> — "but I will also make the son of the slave woman into a nation." God\'s promise to Ishmael is restated: <em>lĕgôy</em> (into a nation) — a significant word: the same promise given to Abraham (12:2: "I will make you a great nation") is given in a modified form to Ishmael. <strong>כִּי זַרְעֲךָ הוּא</strong> (for he is your offspring) — God\'s care for Ishmael is rooted in Ishmael\'s relationship to Abraham, not to Sarah or to the covenant per se. The principle: God\'s covenant does not eliminate his care for those outside the primary covenant line.</p>',
    "14": '<p><strong>וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר</strong> — "Abraham rose early in the morning." The same word as 22:3 (the Akedah) and 20:8 (Abimelech\'s early response to God\'s warning) — the early rising marks urgency in response to divine direction. <strong>וַיִּתֵּן אֶל-הָגָר שָׂם עַל-שִׁכְמָהּ וְאֶת-הַיֶּלֶד</strong> — "he gave to Hagar, putting [them] on her shoulder, and the child" — the Hebrew syntax is difficult: food and water are given, placed on Hagar\'s shoulder, along with the child (how exactly the child was carried with these provisions is unclear). <em>Wayyĕšallĕḥehā</em> (he sent her away) — the same verb used for Adam\'s expulsion from Eden (3:23; שָׁלַח). Hagar departs for the "wilderness of Beersheba" — the dry steppe south of the settled zone.</p>',
    "15": '<p><strong>וַיִּכְלוּ הַמַּיִם מִן-הַחֵמֶת</strong> — "the water in the skin was gone." <em>Ḥēmet</em> (skin bottle, water-skin) — water is life in the desert; the narrative precisely marks the crisis point: without water, the child will die. <strong>וַתַּשְׁלֵךְ אֶת-הַיֶּלֶד תַּחַת אַחַד הַשִּׂיחִם</strong> — "she cast the child under one of the bushes." <em>Šālaḵ</em> (to throw, cast) — the same verb used for casting the Egyptian children into the Nile (Exod 1:22) — Hagar is forced to do to her son what Pharaoh would later do to Hebrew children. The irony that the Egyptian woman abandons her child in the wilderness prefigures the Egyptian king abandoning Hebrew children in the river.</p>',
    "16": '<p><strong>לֹא אֶרְאֶה בְּמוֹת הַיָּלֶד</strong> — "I cannot watch the boy die." Hagar moves away "a bowshot away" — the Hebrew bow-distance (<em>kĕmĕṭaḥăwê qešet</em>) is a precise practical measure: far enough not to see but close enough to hear. <em>Wattiśśāʾ ʾet-qōlāh watēḇk</em> (she lifted up her voice and wept) — the mourning formula; Hagar\'s weeping mirrors her weeping in ch. 16. The mother who received the divine promise of Ishmael\'s greatness (16:10-12) is now at the point of watching him die — the gap between promise and visible reality is absolute.</p>',
    "17": '<p><strong>וַיִּשְׁמַע אֱלֹהִים אֶת-קוֹל הַנַּעַר</strong> (<em>wayyišmaʿ ʾĔlōhîm ʾet-qôl hannāʿar</em>) — "God heard the voice of the boy." The boy\'s name, Ishmael ("God hears"), is enacted: God hears (<em>šāmaʿ</em>) the one whose name means "God hears." The divine hearing is not Hagar\'s weeping but the boy\'s crying — the covenant of the name (16:11: "for the LORD has heard your affliction") is fulfilled in its next generation. <strong>מַלְאַךְ אֱלֹהִים</strong> (angel of God) — the second appearance of the divine messenger to Hagar (cf. 16:7); <em>qārāʾ</em> from heaven (called from heaven) — the heavenly voice rather than the visible manifestation of 16:7.</p>',
    "18": '<p><strong>קוּמִי שְׂאִי אֶת-הַנַּעַר</strong> (<em>qûmî śĕʾî ʾet-hannāʿar</em>) — "rise, lift up the boy." The double imperative (<em>qûmî</em>, rise; <em>śĕʾî</em>, lift up) is urgent. <strong>כִּי-לְגוֹי גָּדוֹל אֲשִׂימֶנּוּ</strong> — "for I will make him into a great nation." The promise is the same as 17:20 (God\'s covenant with Ishmael: "I will make him a great nation") and echoes the Abrahamic promise of 12:2. The angel\'s words repeat the content of the name: hear it again, Hagar — what God said, God will do.</p>',
    "19": '<p><strong>וַיִּפְקַח אֱלֹהִים אֶת-עֵינֶיהָ וַתֵּרֶא בְּאֵר מָיִם</strong> — "God opened her eyes and she saw a well of water." <em>Pāqaḥ</em> (to open, uncover — eyes) — the same verb as in 3:5, 7 where the serpent promises "your eyes will be opened" after eating the forbidden fruit, and in 3:7 where "the eyes of both of them were opened." The ironic reversal is clear: in Eden, eyes opened to shame and knowledge of evil; here, eyes are opened to water and life. The divine eye-opening is mercy, not judgment. The well was presumably there all along — Hagar could not see it until God opened her eyes.</p>',
    "20": '<p><strong>וַיְהִי אֱלֹהִים אֶת-הַנַּעַר</strong> (<em>wayhî ʾĔlōhîm ʾet-hannāʿar</em>) — "God was with the boy." The summary formula <em>YHWH/ʾĔlōhîm was with X</em> is the highest divine-favor statement in the OT narrative (with Joseph, 39:2, 21, 23; with David, 1 Sam 16:18; 18:12, 14; with Jesus, Acts 10:38). Ishmael grows up with the divine presence — he is not abandoned. <strong>וַיְהִי רֹבֶה קַשָּׁת</strong> (he became an archer) — <em>rōbeh qaššāt</em> (bow-shooter, archer) — fulfilling the wild-donkey-man oracle of 16:12: independent, free, skilled in desert survival.</p>',
    "21": '<p><strong>וַתִּקַּח-לוֹ אִמּוֹ אִשָּׁה מֵאֶרֶץ מִצְרָיִם</strong> — "his mother took a wife for him from the land of Egypt." Hagar the Egyptian secures an Egyptian wife for Ishmael — he becomes the ancestor of peoples linked to Egypt, consistent with the Arabian/Ishmaelite peoples of the OT\'s geographic horizon. The mother arranges the marriage (the father\'s role is normally fulfilled here by the mother because Abraham has expelled them) — Hagar exercises the paternal prerogative of marriage arrangement for her son.</p>',
    "22": '<p><strong>אֱלֹהִים עִמְּךָ בְּכֹל אֲשֶׁר-אַתָּה עֹשֶׂה</strong> — "God is with you in all that you do." Abimelech and Phicol recognize the divine presence with Abraham — the same recognition formula that Laban will use (31:5: "God of your father is with you") and that will be repeated for Isaac (26:28) and Joseph (39:2-3). <em>Pîḵōl</em> (Phicol) — the commander of Abimelech\'s forces; his inclusion in the treaty-request elevates it to a state treaty, not merely a personal agreement.</p>',
    "23": '<p><strong>אִם-תִּשְׁקֹר לִי וּלְנִינִי וּלְנֶכְדִּי</strong> — "that you will not deal falsely with me, or with my son\'s son, or with my grandson." <em>Šāqar</em> (to deal falsely, betray — specifically covenantal betrayal, false-dealing within a sworn relationship; cf. Ps 44:17; 89:33). <em>Nîn wāneḵeḏ</em> (offspring and descendant) — a rare pair of terms for extended lineage, appearing also in Job 18:19 and Isa 14:22. Abimelech is asking for a multi-generational treaty — the covenant of kindness he showed Abraham should bind their descendants. <strong>כַּחֶסֶד אֲשֶׁר-עָשִׂיתִי עִמְּךָ</strong> (<em>kaḥeseḏ ʾăšer-ʿāśîtî ʿimmĕḵā</em>) — "as the kindness I have done with you" — <em>ḥeseḏ</em> (covenant-loyalty, steadfast love) is the word for Abimelech\'s conduct: he treated Abraham with <em>ḥeseḏ</em> even after being deceived.</p>',
    "24": '<p><strong>אָנֹכִי אִשָּׁבֵעַ</strong> (<em>ʾānōḵî ʾiššāḇēaʿ</em>, I will swear) — Abraham accepts the treaty request with the emphatic first-person pronoun <em>ʾānōḵî</em> (I, myself) + the Niphal of <em>šāḇaʿ</em> (to swear, bind oneself by oath). The swearing establishes a formal covenant relationship between Abraham and the Philistine king — a non-Israelite political treaty rooted in recognized divine presence.</p>',
    "25": '<p><strong>וְהוֹכִחַ אַבְרָהָם אֶת-אֲבִימֶלֶךְ</strong> (<em>wĕhôkîaḥ ʾaḇrāhām ʾet-ʾăḇîmeleḵ</em>) — "Abraham complained/argued with Abimelech." <em>Yākaḥ</em> (Hiphil, to reprove, argue, bring a legal complaint against) — a formal disputational term; Abraham raises a legal grievance. <strong>עַל-אֹדוֹת בְּאֵר הַמַּיִם</strong> (about a well of water) — water rights in the Negev were a matter of survival; disputes over wells are a recurring motif in the patriarchal narratives (26:15-22; Exod 2:17). Abraham complains that Abimelech\'s servants seized the well he dug.</p>',
    "26": '<p>Abimelech\'s denial: "I do not know who did this thing / you did not tell me / I heard about it only today" — three successive disclaimers creating a formal forensic defense. The three-part denial is a rhetorical unit that completely absolves Abimelech (by his own account) of responsibility for the well-seizure. The narrative does not adjudicate between the claims; it proceeds to the treaty that resolves the dispute.</p>',
    "27": '<p><strong>וַיִּכְרְתוּ שְׁנֵיהֶם בְּרִית</strong> (<em>wayyiḵrĕtû šĕnêhem bĕrît</em>) — "the two of them cut a covenant." <em>Kārat bĕrît</em> (to cut a covenant) — the standard treaty formula (cf. 15:18 for the Abrahamic covenant, 31:44 for Jacob and Laban). The sheep and cattle Abraham gave (v. 27) are both the gift of friendship and possibly the sacrificial animals for the covenant ceremony (parties to a covenant sometimes offered sacrifices at the ratification).</p>',
    "28": '<p><strong>וַיַּצֵּב אַבְרָהָם אֶת-שֶׁבַע כִּבְשֹׂת הַצֹּאן לְבַדְּהֶן</strong> — "Abraham set apart seven ewe lambs by themselves." <em>Šeḇaʿ kĕḇāśôt</em> (seven ewe lambs) — the word <em>šeḇaʿ</em> (seven) is the root of the Beersheba name: <em>bĕʾēr šeḇaʿ</em> = "well of seven" or "well of the oath" (šĕḇuʿāh = oath, from the same root šāḇaʿ). The seven lambs function as an oath-token — a material confirmation of the sworn covenant.</p>',
    "29": '<p>Abimelech\'s question about the seven lambs creates the legal dialogue through which Abraham explains the symbolic significance — a teaching moment embedded in the covenant ceremony. The question-and-answer pattern (Abimelech asks → Abraham explains) is the standard didactic structure for covenant ceremonies and legal transactions in the OT, where formal questioning ensures that all parties understand the legal significance of the symbolic act.</p>',
    "30": '<p><strong>כִּי אֶת-שֶׁבַע כְּבָשֹׂת תִּקַּח מִיָּדִי בַּעֲבוּר תִּהְיֶה-לִּי לְעֵדָה אֲשֶׁר חָפַרְתִּי אֶת-הַבְּאֵר הַזֹּאת</strong> — "the seven lambs you shall accept from my hand so that it may be a witness for me that I dug this well." <em>ʿEḏāh</em> (witness, testimony) — the seven lambs serve as a legal witness object: the acceptance of the lambs by Abimelech constitutes acknowledgment that Abraham dug the well and owns the water rights. Legal documentation in the ANE used symbolic objects as substitute for written contracts.</p>',
    "31": '<p><strong>עַל-כֵּן קָרָא לַמָּקוֹם הַהוּא בְּאֵר שָׁבַע</strong> (<em>ʿal-kēn qārāʾ lammāqôm hahûʾ bĕʾēr šāḇaʿ</em>) — "therefore that place was called Beersheba." The etymology is double: <em>bĕʾēr šāḇaʿ</em> = (1) Well of Seven (<em>šeḇaʿ</em> = seven — the seven lambs); or (2) Well of the Oath (<em>šĕḇuʿāh</em> = oath, from <em>šāḇaʿ</em> = to swear). Both meanings are activated simultaneously — the place name encodes the dual significance of the number seven and the covenant oath. Beersheba will become one of the key patriarchal sites (26:23-25, 33; 28:10; 46:1) and eventually the southern boundary marker of Israel ("from Dan to Beersheba").</p>',
    "32": '<p><strong>אֶרֶץ פְּלִשְׁתִּים</strong> (<em>ʾereṣ pĕlištîm</em>, land of the Philistines) — the anachronistic reference to "the land of the Philistines" is noted by scholars: the Philistines as a settled people in Canaan\'s coastal plain are historically attested from the 12th century BCE (Sea Peoples), later than the patriarchal period. This may reflect: (1) an updating gloss by a later editor; (2) the use of an ancient ethnic name for peoples of that region before the canonical Philistine settlement; (3) a literary identification with the later Philistine territory.</p>',
    "33": '<p><strong>וַיִּטַּע אֶשֶׁל בִּבְאֵר שָׁבַע וַיִּקְרָא-שָׁם בְּשֵׁם יְהוָה אֵל עוֹלָם</strong> — "Abraham planted a tamarisk tree at Beersheba and called there on the name of the LORD, the Eternal God." <em>ʾĒšel</em> (tamarisk) — a tree that provides shade in the harsh Negev; associated with sanctuary or memorial plantings (Saul also plants one in 1 Sam 31:13). <em>ʾĒl ʿôlām</em> (the Eternal God/God of eternity) — Abraham\'s divine name at Beersheba; <em>ʿôlām</em> is here used as a divine epithet ("the Eternal One") rather than modifying the covenant (cf. 17:7, 13, 19 where <em>ʿôlām</em> modifies the covenant itself). The attribute of God\'s eternal nature is new in the Genesis divine-name vocabulary.</p>',
    "34": '<p><strong>וַיָּגָר אַבְרָהָם בְּאֶרֶץ פְּלִשְׁתִּים יָמִים רַבִּים</strong> — "Abraham sojourned in the land of the Philistines many days." <em>Yāmîm rabbîm</em> (many days) — an indefinite long period; the same phrase used for the sojourning of Jacob (37:34) and others. The extended Beersheba period forms the interval before the Akedah of ch. 22 — the narrative pause before the climactic test. Abraham the sojourner continues his pattern: possessing nothing permanently in the promised land, living as a guest among its inhabitants.</p>'
  },
  "22": {
    "1": '<p><strong>וַיְהִי אַחַר הַדְּבָרִים הָאֵלֶּה</strong> (<em>wayhî ʾaḥar haddĕḇārîm hāʾēlleh</em>) — "after these things." The narrative connective following the treaty and Beersheba period. <strong>וְהָאֱלֹהִים נִסָּה אֶת-אַבְרָהָם</strong> (<em>wĕhāʾĔlōhîm nissāh ʾet-ʾaḇrāhām</em>) — "and God tested Abraham." <em>Nissāh</em> (Piel of <em>nāsāh</em>, to test, try, prove) — the narrator reveals the test\'s nature immediately, so the reader knows what Abraham does not. The same verb is used for the wilderness testing of Israel (Exod 15:25; 16:4; 20:20; Deut 8:2, 16). Testing (<em>nissāyôn</em>) in the OT is not divine cruelty but divine disclosure: the test reveals what is already in the heart. <em>Hinnēnî</em> (here I am, ready, present) — Abraham\'s response; the formula of radical availability to God\'s call (used also in Exod 3:4; Isa 6:8).</p>',
    "2": '<p><strong>קַח-נָא אֶת-בִּנְךָ אֶת-יְחִידְךָ אֲשֶׁר-אָהַבְתָּ אֶת-יִצְחָק</strong> — "take now your son, your only son, whom you love, Isaac." The five-fold specification is deliberately cumulative: (1) <em>bĕnḵā</em> (your son); (2) <em>yĕḥîḏĕḵā</em> (your only son — from <em>yāḥîḏ</em>, only, unique, alone); (3) <em>ʾăšer-ʾāhaḇtā</em> (whom you love — the first use of the verb <em>ʾāhab</em>, love, in the OT); (4) <em>ʾet-yiṣḥāq</em> (Isaac — named last, after the emotional buildup). John 3:16 echoes this structure: "his one and only Son" (<em>monogenē</em>) and "loved" (<em>ēgápēsen</em>). <strong>לֶךְ-לְךָ</strong> — the second great <em>lēḵ-lĕḵā</em> command, matching 12:1; the two commands bracket the Abraham narrative.</p>',
    "3": '<p><strong>וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר</strong> — "Abraham rose early in the morning." No recorded hesitation, no dialogue with Sarah, no delay — the narrative\'s silence on the night between the command and the morning is as significant as any speech could be. <em>Wayyaḥăbōš ʾet-ḥămōrô</em> (he saddled his donkey) — the patriarch himself saddles the animal, not his servants; the personal involvement signals the seriousness and directness of the response. <strong>וַיְבַקַּע עֲצֵי עֹלָה</strong> (he cut the wood for the burnt offering) — the preparatory work is complete before the journey begins; Abraham takes the wood, the fire (<em>ʾēš</em>), and the knife (<em>maʾăḵelet</em>, cleaver, knife for slaughter).</p>',
    "4": '<p><strong>בַּיּוֹם הַשְּׁלִישִׁי</strong> (<em>bayyôm haššĕlîšî</em>, on the third day) — "the third day" in the OT carries the weight of divine action following a period of apparent inactivity: deliverance at the Red Sea (Exod 14-15 measured from departure), resurrection (Hos 6:2; Jon 1:17; 1 Cor 15:4), the giving of the Torah (Exod 19:11, 16). Hebrews 11:19 explicitly reads the Akedah through the resurrection lens: Abraham "considered that God was able even to raise him from the dead, from which, figuratively speaking, he did receive him back." The three-day journey places the Akedah in the theological register of death-and-restoration. <strong>וַיַּשָּׂא אַבְרָהָם אֶת-עֵינָיו</strong> — "Abraham lifted up his eyes" — the seeing-command formula of 13:14 now fulfilled by Abraham\'s own initiative.</p>',
    "5": '<p><strong>שְׁבוּ-לָכֶם פֹּה עִם-הַחֲמוֹר</strong> — "stay here with the donkey." The two servants are left behind; father and son go alone. <strong>אֲנִי וְהַנַּעַר נֵלְכָה עַד-כֹּה</strong> (<em>ʾănî wĕhannāʿar nēlĕḵāh ʿaḏ-kōh</em>) — "I and the boy will go over there." <strong>וְנִשְׁתַּחֲוֶה וְנָשׁוּבָה אֲלֵיכֶם</strong> (<em>wĕništaḥăweh wĕnāšûḇāh ʾălêḵem</em>) — "we will worship and we will return to you." The first-person plural "we" is either (1) Abraham\'s faith statement: he believed both of them would return (Heb 11:19); or (2) a social euphemism to prevent the servants from interfering. The grammar permits both readings; the theology of Heb 11:19 takes the first seriously.</p>',
    "6": '<p><strong>וַיַּשֶׂם אַבְרָהָם אֶת-עֲצֵי הָעֹלָה עַל-יִצְחָק בְּנוֹ</strong> — "Abraham placed the wood of the burnt offering on his son Isaac." The wood is placed on the son — a detail noted in patristic reading as a type of the cross-bearing (John 19:17: Jesus "carrying his own cross"). Whether intended by the narrator or not, the structural parallel is precise: the son carries the instrument of his own sacrifice. <strong>וַיִּקַּח בְּיָדוֹ אֶת-הָאֵשׁ וְאֶת-הַמַּאֲכֶלֶת</strong> (he took in his hand the fire and the knife) — Abraham carries the dangerous items himself, protecting Isaac from the fire and the knife.</p>',
    "7": '<p><strong>הִנֶּה הָאֵשׁ וְהָעֵצִים וְאַיֵּה הַשֶּׂה לְעֹלָה</strong> — "the fire and the wood are here, but where is the lamb for the burnt offering?" Isaac\'s question is innocent and devastating: he sees the preparations, notes the missing element, asks. <em>Śeh</em> (lamb, sheep/goat for offering) — the specific sacrificial animal vocabulary. The question hangs in the air as the central tension of the narrative: where is the offering? The answer of v. 8 is at once evasive and prophetic.</p>',
    "8": '<p><strong>אֱלֹהִים יִרְאֶה-לּוֹ הַשֶּׂה לְעֹלָה בְּנִי</strong> — "God will provide for himself the lamb for the burnt offering, my son." <em>Yirʾeh-llô</em> — the reflexive dative (<em>lô</em>, for himself) with the verb <em>rāʾāh</em> (to see): "God will see/provide for himself." This is the etymological basis of the name YHWH-Yireh in v. 14 (<em>YHWH yirʾeh</em>): where God sees, God provides. The expression is ambiguous in the moment — Abraham may be speaking a genuine theological principle without knowing how it will apply; the narrative reveals that the principle was literally and immediately true. <strong>וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו</strong> (the two of them went together) — the phrase is repeated from v. 6 and will occur again after Isaac\'s question: "together" (<em>yaḥdāw</em>) at every stage, despite the terrible knowledge Abraham carries.</p>',
    "9": '<p><strong>וַיַּעֲקֹד אֶת-יִצְחָק בְּנוֹ</strong> (<em>wayyaʿăqōḏ ʾet-yiṣḥāq bĕnô</em>) — "he bound his son Isaac." <em>ʿĀqaḏ</em> (to bind, tie — specifically the binding of feet or limbs; this verb appears only here in the OT) — the Akedah takes its name from this word. The binding of Isaac is the technical term for the preparatory restraint of a sacrifice before slaughter. <strong>וַיָּשֶׂם אֹתוֹ עַל-הַמִּזְבֵּחַ מִמַּעַל לָעֵצִים</strong> (he laid him on the altar, on top of the wood) — the altar, the wood, the bound son: the preparation is complete. There is no recorded resistance from Isaac, no recorded cry from Abraham.</p>',
    "10": '<p><strong>וַיִּשְׁלַח אַבְרָהָם אֶת-יָדוֹ וַיִּקַּח אֶת-הַמַּאֲכֶלֶת לִשְׁחֹט אֶת-בְּנוֹ</strong> — "Abraham stretched out his hand and took the knife to slaughter his son." The verb <em>šāḥaṭ</em> (to slaughter, kill in the ritual sense used for sacrificial animals — cf. Lev 1:5; 3:2, 8, 13) confirms that the act Abraham was about to perform was not murder but sacrifice: he was treating his son as a sacrificial animal, as God had commanded. The hand is stretched out (<em>šālaḥ yāḏ</em>) — the same phrase as when God stretched out his hand in judgment (Exod 7:19; 9:15).</p>',
    "11": '<p><strong>וַיִּקְרָא אֵלָיו מַלְאַךְ יְהוָה מִן-הַשָּׁמַיִם</strong> — "the angel of the LORD called to him from heaven." The intervention is from heaven — divine authority from above; in ch. 16 and 21 the angel appeared in the desert; here the heavenly call matches the elevated location (the mountain) and the elevation of the stakes. <strong>אַבְרָהָם אַבְרָהָם</strong> — the doubled name is the divine address of urgent importance: Moses! Moses! (Exod 3:4); Samuel! Samuel! (1 Sam 3:10); Martha, Martha! (Luke 10:41); Saul, Saul! (Acts 9:4). The repetition halts the action at the critical moment. <em>Hinnēnî</em> — "here I am" — the same response as v. 1; Abraham remains in readiness even at the moment of the knife.</p>',
    "12": '<p><strong>כִּי עַתָּה יָדַעְתִּי כִּי-יְרֵא אֱלֹהִים אַתָּה</strong> (<em>kî ʿattāh yāḏaʿtî kî-yĕrēʾ ʾĔlōhîm ʾattāh</em>) — "for now I know that you are a God-fearer." <em>Yāḏaʿtî</em> (I have come to know, I know) — the divine statement of knowing after the test does not imply prior ignorance; it is a forensic declaration: the test has produced observable evidence that the claim of faith is real. <strong>לֹא חָשַׂכְתָּ אֶת-בִּנְךָ אֶת-יְחִידְךָ מִמֶּנִּי</strong> — "you have not withheld your son, your only son, from me." <em>Ḥāśaḵ</em> (to withhold, spare, hold back) — Paul cites the parallel in Rom 8:32: "He who did not spare (<em>ouk epheisato</em>) his own Son but gave him up for us all" — the language of the Akedah is applied to the Father\'s giving of the Son.</p>',
    "13": '<p><strong>אַיִל אַחַר נֶאֱחַז בַּסְּבַךְ בְּקַרְנָיו</strong> — "a ram caught in a thicket by its horns." <em>ʾAyil</em> (ram, adult male sheep — specifically the animal used in burnt offerings, Lev 8:18-21; Num 29:2) — the animal is a ram, not the <em>śeh</em> (lamb) that Isaac asked about. The ram appears caught — God\'s provision arrives already prepared, already there; the ram was caught in the thicket while Abraham was raising the knife. <em>Wayyiqaḥ ʾet-hāʾayil wayyaʿălēhû lĕʿōlāh taḥat bĕnô</em> (he took the ram and offered it as a burnt offering instead of his son) — <em>taḥat</em> (instead of, in place of, as a substitute for) — substitutionary sacrifice: the ram dies in the place of the son.</p>',
    "15": '<p><strong>וַיִּקְרָא מַלְאַךְ יְהוָה אֶל-אַבְרָהָם שֵׁנִית מִן-הַשָּׁמָיִם</strong> — "the angel of the LORD called to Abraham a second time from heaven." The second heavenly word (vv. 16-18) is the divine oath — the highest level of divine commitment possible. The first call (vv. 11-12) halted the sacrifice; the second call confirms the covenant in the most solemn form. The two calls frame the Akedah\'s resolution: rescue (first call) and covenant renewal (second call).</p>',
    "16": '<p><strong>בִּי נִשְׁבַּעְתִּי</strong> (<em>bî nišbaʿtî</em>, by myself I have sworn) — the divine self-oath. God swears by himself because there is nothing greater to swear by — this is the theological argument of Heb 6:13-17: "since he had no one greater by whom to swear, he swore by himself." The self-oath (<em>bî nišbaʿtî</em> = literally "by me I have sworn") elevates the covenant to its highest possible register. <strong>יַעַן אֲשֶׁר עָשִׂיתָ אֶת-הַדָּבָר הַזֶּה וְלֹא חָשַׂכְתָּ אֶת-בִּנְךָ אֶת-יְחִידֶךָ</strong> — "because you have done this and have not withheld your son, your only son" — the covenant renewal is explicitly conditional on Abraham\'s obedience, but the oath makes the fulfillment unconditional once given.</p>',
    "17": '<p><strong>כִּי-בָרֵךְ אֲבָרֶכְךָ וְהַרְבָּה אַרְבֶּה אֶת-זַרְעֲךָ</strong> (<em>kî-ḇārēḵ ʾăḇārĕḵĕḵā wĕharbbāh ʾarbbeh ʾet-zarʿĕḵā</em>) — "I will surely bless you and greatly multiply your offspring." Two emphatic infinitive absolutes (<em>bārēḵ ʾăḇārĕḵĕḵā</em>; <em>harbāh ʾarbbeh</em>) — the most emphatic Hebrew grammar for absolute certainty. <strong>כְּכוֹכְבֵי הַשָּׁמַיִם וְכַחוֹל אֲשֶׁר עַל-שְׂפַת הַיָּם</strong> — "as the stars of the sky and as the sand on the seashore" — both innumerability images combined in a single verse, restating and expanding 15:5 (stars) and 13:16 (dust). The offspring promise restated after the test with maximum rhetorical force. <strong>וְיִרַשׁ זַרְעֲךָ אֵת שַׁעַר אֹיְבָיו</strong> — "your offspring will possess the gate of their enemies" — the gate (<em>šaʿar</em>) = the city; possessing the gate = conquering the city; the promise anticipates the conquest and establishment of the Davidic kingdom.</p>',
    "18": '<p><strong>וְהִתְבָּרֲכוּ בְזַרְעֲךָ כֹּל גּוֹיֵי הָאָרֶץ</strong> — "all nations of the earth will be blessed through your offspring." <em>Wĕhitbārăḵû</em> — Hithpael (reflexive-passive: they will bless themselves through / they will be blessed through). The form here (Hithpael) creates ambiguity between reflexive ("all nations will bless themselves by your offspring") and passive ("all nations will be blessed through your offspring") — Gal 3:8 and Acts 3:25 quote this verse as passive (echoing 12:3 where the Niphal form appears). The promise ends with the most universal scope: <em>kol gôyê hāʾāreṣ</em> (all nations of the earth), reaching far beyond the land of Canaan to embrace the entire human community.</p>',
    "19": '<p><strong>וַיָּשָׁב אַבְרָהָם אֶל-נְעָרָיו</strong> — "Abraham returned to his young men." The return is recorded briefly — no dialogue, no emotional commentary. The narrative lacunism is itself a feature: what passed between Abraham and Isaac on the descent is not told. <em>Wayyāqom wayyēlĕḵû yaḥdāw ʾel-bĕʾēr šāḇaʿ</em> (they rose and went together to Beersheba) — "together" (<em>yaḥdāw</em>) again: they went up together (v. 6), came down together (implied), and return together. The relationship survives the test intact.</p>',
    "20": '<p>The genealogical notice of Nahor\'s family (vv. 20-24) is positioned here for a narrative purpose: Rebekah appears as Bethuel\'s daughter (v. 23). The next major action in the Abraham narrative will be finding Isaac a wife (ch. 24), and this genealogy introduces Rebekah into the story before the betrothal narrative begins. The notice also signals that the covenant line (which narrowed through Isaac) will be continued by a wife from the family of Nahor — the broader Abraham family, not a Canaanite woman.</p>',
    "21": '<p>Nahor\'s eight sons through Milcah: <strong>עוּץ</strong> (<em>ʿûṣ</em>, Uz) is the firstborn — the land of Uz is Job\'s homeland (Job 1:1); <strong>בּוּז</strong> (<em>bûz</em>, Buz) gives his name to the Buzite clan (Job 32:2 — Elihu the Buzite). The Nahorite genealogy thus connects to the Job tradition: Job\'s world is the world of the broader Semitic family descended from Nahor. The connections between the patriarchal and wisdom literature traditions run through these genealogical notices.</p>',
    "22": '<p>Kesed, Hazo, Pildash, Jidlaph, and Bethuel — these Nahorite names map onto the Aramean/northern Mesopotamian tribal geography. <strong>בְּתוּאֵל</strong> (<em>Bĕtûʾēl</em>, Bethuel) — "man of God" or possibly "daughter of God" (the name is unusual; some read it as "house of El") — the father of Rebekah and father-in-law of Isaac; he appears again in 24:15, 24, 47, 50; 25:20; 28:2, 5. The genealogy\'s descent to Bethuel is the narrative point of the list: it establishes Rebekah\'s family pedigree within the Nahorite-Semitic clan structure.</p>',
    "23": '<p><strong>וּבְתוּאֵל יָלַד אֶת-רִבְקָה</strong> (<em>ûḇĕtûʾēl yālaḏ ʾet-riḇqāh</em>) — "Bethuel fathered Rebekah." <em>Riḇqāh</em> (Rebekah) — the name is introduced without commentary; she is "born" into the narrative at the moment the story needs her. The positioning of Rebekah\'s introduction immediately after the Akedah (where Isaac\'s existence is confirmed and the covenant line secured) and before the wife-search of ch. 24 is structurally elegant: the Akedah tests and secures Isaac; the genealogy introduces his future wife; ch. 24 brings them together.</p>',
    "24": '<p><strong>וּפִילַגְשׁוֹ וּשְׁמָהּ רְאוּמָה</strong> (<em>ûpîlaḡšô ûšĕmāh rĕʾûmāh</em>) — "his concubine, whose name was Reumah." <em>Pîleḡeš</em> (concubine) — a secondary wife without the full legal status of the primary wife; a recognized category of marriage in the ANE. Nahor\'s four sons by Reumah complete his twelve sons total (eight through Milcah, four through Reumah) — a number that may deliberately parallel the twelve tribes of Israel who descend from Abraham\'s twelve-grandson structure (Ishmael also has twelve princes, 17:20; 25:12-16). The narrative geometry of twelve descendants is a recurring organizational principle.</p>'
  },
  "23": {
    "1": '<p><strong>וַיִּהְיוּ חַיֵּי שָׂרָה מֵאָה שָׁנָה וְעֶשְׂרִים שָׁנָה וְשֶׁבַע שָׁנִים</strong> — "The years of Sarah\'s life were one hundred years and twenty years and seven years." The unusual enumeration (one hundred + twenty + seven, rather than the standard "127 years") may emphasize each unit separately or reflect an archaic form of numerical notation. Sarah is the only woman in the OT whose age at death is explicitly recorded — the covenant wife\'s lifespan is narratively as significant as the patriarch\'s. The phrase <em>ḥayyê śārāh</em> (the life/years of Sarah) gives the chapter its traditional Jewish title (<em>Parashat Ḥayyê Śārāh</em>).</p>',
    "2": '<p><strong>וַתָּמָת שָׂרָה בְּקִרְיַת אַרְבַּע הִוא חֶבְרוֹן</strong> — "Sarah died in Kiriath-arba, that is Hebron." <em>Qiryat ʾarbaʿ</em> (city of four / city of Arba) — the ancient name for Hebron; Josh 14:15 identifies Arba as "the greatest man among the Anakim" (a giant). The parenthetical "(that is, Hebron)" uses the later, better-known name for the reader. Hebron is where Abraham had his altar (13:18) and his Amorite allies (14:13, 24). <strong>לִסְפֹּד לְשָׂרָה וְלִבְכֹּתָהּ</strong> (to mourn and to weep for Sarah) — two verbs: <em>sāpad</em> (to strike the breast, wail formally in lamentation — a ritualized mourning gesture) and <em>bākāh</em> (to weep — the emotional tears). Both forms of mourning are given to Sarah.</p>',
    "3": '<p><strong>מֵעַל פְּנֵי מֵתוֹ</strong> (<em>mēʿal pĕnê mētô</em>, from before/beside his dead) — "from beside his dead wife." The Hebrew literally is "from the face of his dead one" — <em>pāneh</em> (face) in proximity language; Abraham had been sitting with the body, then rises to conduct the business of burial. The posture of rising from beside the dead body marks the transition from grief to practical action. <strong>וַיְדַבֵּר אֶל-בְּנֵי-חֵת</strong> (he spoke to the sons of Heth) — the Hittites (<em>ḥittîm</em>) are the resident population of Hebron; Abraham must negotiate with them for burial rights.</p>',
    "4": '<p><strong>גֵּר-וְתוֹשָׁב אָנֹכִי עִמָּכֶם</strong> (<em>gēr-wĕtôšāḇ ʾānōḵî ʿimmāḵem</em>) — "I am a sojourner and resident-alien among you." The double status: <em>gēr</em> (sojourner, resident alien without citizen rights, legal protection through hospitality conventions) + <em>tôšāḇ</em> (temporary settler, one who dwells temporarily in a place that belongs to others). The combined phrase appears in Lev 25:23 where God tells Israel that "the land is mine; for you are strangers and sojourners (<em>gērîm wĕtôšāḇîm</em>) with me." The self-description is Abraham\'s own — he is the covenant heir of the land and yet has no legal ownership of any of it; he must buy burial space from its current occupants. 1 Pet 2:11 echoes this self-identification for Christians in the world.</p>',
    "5": '<p>The Hittites\' response (vv. 5-6) follows a formal protocol: they address Abraham with honorific recognition, concede his request in principle, and offer the most generous possible terms — all family tombs are open to him. The negotiation unfolds in the formal pattern of ANE public transaction: open offer → counter-request (Abraham specifies what he actually wants) → second negotiation round (vv. 7-16). The repetition of bowing (<em>wayyišaḥû</em>, v. 7) and formal address marks each stage of the legal protocol.</p>',
    "6": '<p><strong>נְשִׂיא אֱלֹהִים אַתָּה בְּתוֹכֵנוּ</strong> (<em>nĕśîʾ ʾĔlōhîm ʾattāh bĕtôḵēnû</em>) — "you are a prince of God among us." <em>Nāśîʾ</em> (chieftain, prince, elevated one) — the highest social title the Hittites can give; <em>ʾĔlōhîm</em> as a superlative intensifier (a "divine/god-like prince") or literally "God\'s prince" — acknowledging that divine blessing rests on Abraham. The same recognition occurs with Abimelech (21:22: "God is with you in all you do"). The pagan recognition of God\'s blessing on Abraham is a recurring narrative pattern. <strong>בְּמִבְחַר קְבָרֵינוּ קְבֹר אֶת-מֵתֶךָ</strong> — "bury your dead in the choicest of our tombs" — the offer is maximally generous; Abraham will nevertheless insist on buying a specific site.</p>',
    "7": '<p><strong>וַיָּקָם אַבְרָהָם וַיִּשְׁתַּחוּ לְעַם-הָאָרֶץ</strong> — "Abraham rose and bowed down before the people of the land." <em>Wayyiqqom wayyištaḥû</em> — rising and bowing is the formal greeting gesture in ANE diplomatic and legal contexts; the bowing here acknowledges the Hittites\' authority over their land and their willingness to negotiate. The politeness is part of the legal protocol — Abraham must be deferential to secure the sale on terms he desires.</p>',
    "8": '<p><strong>אִם-יֶשׁ אֶת-נַפְשְׁכֶם לִקְבֹּר אֶת-מֵתִי מִלְּפָנַי</strong> — "if you are willing to bury my dead from before me." The Hebrew idiom <em>im-yēš ʾet-napšĕḵem</em> (if it is with your soul = if it is your will) treats the soul/will as the seat of desire and intention. Abraham frames his request as conditional on their genuine willingness — he is not demanding but soliciting consent. <strong>שִׁמְעוּנִי וּפִגְעוּ-לִי בְּעֶפְרוֹן</strong> — "hear me and intercede for me with Ephron" — <em>pāgaʿ</em> (to meet, encounter, fall upon; in the Hiphil: to cause to meet, to intercede, to approach on someone\'s behalf) — Abraham asks the assembly to approach Ephron as his intermediaries.</p>',
    "9": '<p><strong>מְעָרַת הַמַּכְפֵּלָה אֲשֶׁר-לוֹ אֲשֶׁר בִּקְצֵה שָׂדֵהוּ</strong> — "the cave of Machpelah which belongs to him, which is at the end of his field." <em>Maḵpēlāh</em> — from <em>kāpal</em> (to double, fold over); possibly "the double cave" — a cave with two chambers. <strong>בְּכֶסֶף מָלֵא</strong> (<em>bĕḵeseḵ mālēʾ</em>, for the full price) — Abraham insists on paying the full market value; he will not receive the burial ground as a gift (which would leave a claim relationship on the property) or at a reduced price. Full payment = full legal title without ongoing obligation. The cave at Machpelah becomes the family tomb: Sarah (23:19), Abraham (25:9), Isaac and Rebekah, and Jacob and Leah (49:29-32; 50:13) will all be buried there.</p>',
    "10": '<p><strong>וְעֶפְרוֹן יֹשֵׁב בְּתוֹךְ בְּנֵי-חֵת</strong> — "Ephron was sitting among the sons of Heth." Ephron was present in the assembly from the beginning — the narrative had been describing the community\'s corporate response; now the specific property owner is identified. The gate (<em>šaʿar</em>) is the commercial and judicial center of the ancient city: contracts, legal cases, marriages, and business were conducted "at the gate" (Ruth 4:1-12; Deut 21:19; Prov 31:23; Amos 5:15). Ephron responds publicly, in the hearing of all — the transaction is legally witnessed from the start.</p>',
    "11": '<p><strong>לֹא-אֲדֹנִי שְׁמָעֵנִי הַשָּׂדֶה נָתַתִּי לָךְ</strong> — "No, my lord, hear me: I give you the field." Ephron\'s initial offer is the field plus the cave as a gift — three times he uses <em>nātatî lĕḵā</em> (I give to you): "I give you the field," "I give you the cave," "I give it to you in the presence of my people." The triple offer of a free gift is a formal ANE negotiating posture — generosity is offered publicly; the expected response is that the buyer will insist on paying. A gift-acceptance would create dependency and ongoing obligation; a purchase creates clean ownership.</p>',
    "12": '<p><strong>וַיִּשְׁתַּחוּ אַבְרָהָם לִפְנֵי עַם הָאָרֶץ</strong> — "Abraham bowed before the people of the land." The second bow acknowledges Ephron\'s offer and the community\'s witnessing role. The repetition of bowing (vv. 7 and 12) frames Abraham\'s second speech; each bow marks a stage of negotiation. The public assembly functions as the legal court witnessing every step of the transaction.</p>',
    "13": '<p><strong>אַךְ אִם-אַתָּה לוּ שְׁמָעֵנִי נָתַתִּי כֶּסֶף הַשָּׂדֶה קַח מִמֶּנִּי</strong> — "but please, if you will hear me — I will give the price of the field; accept it from me." Abraham insists on paying: <em>keseḵ hassāḏeh</em> (the silver/price of the field) — he will pay the commercial value. <em>Qah mimmennî</em> (accept from me) — the polite imperative requesting that Ephron receive payment. By insisting on payment, Abraham converts the gift-offer into a purchase, securing clean legal title without ongoing obligation to the Hittite community.</p>',
    "14": '<p>The transition verse — Ephron\'s reply names the price in v. 15. The formal structure of the negotiation (offer → counter → price-naming → payment) follows attested ANE patterns for real-estate transactions. The speech formula <em>wayyaʿan ʾeprôn ʾet-ʾaḇrāhām</em> (Ephron answered Abraham) marks the decisive turn in the negotiation: the price will now be stated publicly, before witnesses.</p>',
    "15": '<p><strong>אַרְבַּע מֵאוֹת שֶׁקֶל-כֶּסֶף בֵּינִי וּבֵינְךָ מַה-הִוא</strong> — "four hundred shekels of silver — what is that between you and me?" The price named publicly is 400 shekels of silver — a high price for a field and cave. Comparable ANE property prices suggest 400 shekels is a premium price (Jeremiah purchases a field for 17 shekels, Jer 32:9; David purchases the threshing floor for 50 shekels, 2 Sam 24:24). Ephron\'s "what is that between you and me?" dismisses the price as negligible — a social fiction that simultaneously names the price and signals willingness to close the transaction.</p>',
    "16": '<p><strong>וַיִּשְׁקֹל אַבְרָהָם לְעֶפְרֹן אֶת-הַכֶּסֶף</strong> (<em>wayyišqōl ʾaḇrāhām lĕʿeprōn ʾet-hakkeseḵ</em>) — "Abraham weighed out to Ephron the silver." <em>Šāqal</em> (to weigh) — the verb from which <em>šeqel</em> (shekel) is derived; the shekel was originally a weight standard, not a minted coin; silver was weighed on a balance scale in transactions. <strong>עֹבֵר לַסֹּחֵר</strong> (<em>ʿōḇēr lassōḥēr</em>, current among merchants) — silver at the weight-standard that passed/was accepted in commercial transactions; the commercial quality and purity specification ensures that both parties received equivalent value by recognized standards.</p>',
    "17": '<p>The deed-of-sale is recorded with legal precision. <strong>הַשָּׂדֶה וְהַמְּעָרָה אֲשֶׁר-בּוֹ וְכָל-הָעֵץ אֲשֶׁר בַּשָּׂדֶה</strong> — "the field and the cave in it and all the trees within the field" — three components: the field (land), the cave (specific structure), all trees within the borders (everything on the land). ANE property deeds commonly listed all components of the property, including trees, because trees represented independent value (for fruit, timber, shade). The precision mirrors actual ancient property deeds found at Nuzi and Ugarit.</p>',
    "18": '<p><strong>לְאַבְרָהָם לְמִקְנָה לְעֵינֵי בְנֵי-חֵת</strong> — "to Abraham as a possession, in the eyes of the sons of Heth." <em>Miqnāh</em> (purchase, acquisition, something bought) — the key legal word: Abraham now owns the Machpelah by purchase, not by gift or divine covenant alone. <strong>בְּכֹל בָּאֵי שַׁעַר-עִירוֹ</strong> (before all who came in at the gate of his city) — the witnesses are "all who came in at the gate" — the entire civic assembly that regularly passes through the city gate is witness. Public transaction at the gate is the ANE equivalent of registered legal deed: the community is the witness.</p>',
    "19": '<p><strong>וְאַחֲרֵי-כֵן קָבַר אַבְרָהָם אֶת-שָׂרָה אִשְׁתּוֹ</strong> — "afterward Abraham buried Sarah his wife." The legal transaction (vv. 3-18) precedes the burial — proper legal title secured before burial takes place. The burial location: <em>bĕmĕʿārat śĕḏeh hamaḵpēlāh ʿal-pĕnê mamrēʾ hîʾ ḥeḇrôn bĕʾereṣ kĕnaʿan</em> (in the cave of the field of Machpelah, before Mamre, which is Hebron, in the land of Canaan) — the full legal description of the burial site, exactly as in the deed (vv. 17-18). The repetition of the full description confirms that the burial fulfilled the terms of the purchase.</p>',
    "20": '<p><strong>וַיָּקָם הַשָּׂדֶה וְהַמְּעָרָה אֲשֶׁר-בּוֹ לְאַבְרָהָם לַאֲחֻזַּת-קָבֶר מֵאֵת בְּנֵי-חֵת</strong> — "so the field and the cave in it were confirmed/transferred to Abraham as a burial possession from the sons of Heth." <em>Wayyāqom</em> (and it was confirmed/established, rose — Qal imperfect of <em>qûm</em>, to rise, stand, be confirmed; in legal contexts: to be established, confirmed as valid) — the deed is legally confirmed and standing. <em>ʾAḥuzzat-qāḇer</em> (burial possession/burial holding) — <em>ʾăḥuzzāh</em> (possession, holding, land title) is the legal term for territorial ownership used in the land-grant contexts (cf. Lev 25:10-13 for family land returns; Num 27:4; Josh 21:12). Abraham\'s one piece of legally owned land in all of Canaan is a burial cave — the covenant heir who was promised the whole land owns only a tomb.</p>'
  }
}

